vDateField is my custom directive to add the support to default date widget of django admin.
Since that date picker is developed in plan javascript, I had the need to trigger a 'change' event to my input field and the listen to this event to update the ng-model variable.

```javascript
contract_form_app.directive('vDateField', [function() {
    return {
        require: "ngModel",
        restrict: "A",
        link: function(scope, element, attrs, ngModelCtrl) {
            element.addClass("vDateField");
            var updateModel = function (dateText) {
                scope.$apply(function () {
                    ngModelCtrl.$setViewValue(dateText);
                });
            };
            django.jQuery('input').on('change', function() {
                updateModel(element.val());
            });
        }
    };
}]);
```

