```python
from traitlets import validate
class IntRangeSliderGap(widgets.IntRangeSlider):
    @validate('value')
    def enforce_gap(self, proposal):
        gap=1
        min, max = proposal.value
        oldmin, oldmax = self.value

        if min == self.max:
            min -= 1
        
        if (max-min) < gap:
            if oldmin == min:
                # max changed
                max = min + gap
            else:
                min = max - gap
        return (min, max)
```

